import React from 'react';
import { Link } from 'react-router-dom';
import logo from '../assets/logo.png'; // make sure the path matches your file

const Navbar = () => (
  <nav className="bg-white shadow-md p-4 flex justify-between items-center">
    <Link to="/" className="flex items-center space-x-2">
      <img src={logo} alt="Ila Café Logo" className="h-10 w-auto" />
      <span className="text-xl font-bold text-orange-600 hidden sm:inline">Ila Café</span>
    </Link>
    <div className="space-x-4 text-sm font-medium text-gray-700">
      <Link to="/">Home</Link>
      <Link to="/menu">Menu</Link>
      <Link to="/about">About</Link>
      <Link to="/contact">Contact</Link>
    </div>
  </nav>
);

export default Navbar;
